// --- Usage metering -------------------------------------------------------
// Product-neutral credit/usage primitives consumed through
// PostgresMeteringStore. Amounts are integer micros of a host-defined
// currency unit; the embedding app owns pricing, currency, and grant policy.

export const creditGrants = pgTable(
  'boring_credit_grants',
  {
    id: uuid('id')
      .default(sql`gen_random_uuid()`)
      .primaryKey(),
    userId: text('user_id').notNull(),
    amountMicros: bigint('amount_micros', { mode: 'number' }).notNull(),
    reason: text('reason').notNull(),
    expiresAt: timestamp('expires_at'),
    createdAt: timestamp('created_at').defaultNow().notNull(),
  },
  (table) => [
    uniqueIndex('boring_credit_grants_user_reason_idx').on(table.userId, table.reason),
    check('boring_credit_grants_amount_check', sql`${table.amountMicros} > 0`),
  ],
)

// One row per purchase order, keyed by the provider order id (PRIMARY KEY) so the
// purchase lifecycle is globally idempotent per order. status models the lifecycle:
//   'granted'        — credits were minted for this order
//   'refunded'       — refunded/disputed; either a tombstone written BEFORE any
//                      grant (user_id/amount null) so a late order_created never
//                      grants, or a granted row transitioned after revocation.
//   'refund_pending' — a PARTIAL refund arrived before order_created; the pending
//                      fraction (pending_refund_ppm) is applied when the grant
//                      lands (grant net of the refund) instead of being lost.
// userId/amountMicros are nullable to allow a pre-grant tombstone.
export const creditPurchases = pgTable(
  'boring_credit_purchases',
  {
    orderId: text('order_id').primaryKey(),
    userId: text('user_id'),
    amountMicros: bigint('amount_micros', { mode: 'number' }),
    status: text('status').notNull().default('granted'),
    source: text('source').notNull().default('lemonsqueezy'),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    refundedAt: timestamp('refunded_at'),
    /** Cumulative credit micros already revoked for this order (supports
     * repeated partial refunds without double-debiting). */
    refundedMicros: bigint('refunded_micros', { mode: 'number' }),
    /** Pending refund fraction in parts-per-million (fraction × 1e6), set when a
     * partial refund arrives before the grant; applied at grant time. */
    pendingRefundPpm: bigint('pending_refund_ppm', { mode: 'number' }),
    /** Provider identity captured at grant time, for audit/reconcile and to match
     * a later refund against the order we actually credited. */
    storeId: text('store_id'),
    testMode: boolean('test_mode'),
    currency: text('currency'),
    variantId: text('variant_id'),
  },
  (table) => [
    index('boring_credit_purchases_user_idx').on(table.userId),
    check('boring_credit_purchases_amount_check', sql`${table.amountMicros} IS NULL OR ${table.amountMicros} > 0`),
    check('boring_credit_purchases_status_check', sql`${table.status} IN ('granted', 'refunded', 'refund_pending')`),
    // A granted row must carry the credited user + amount; a pre-grant tombstone
    // ('refunded' full, or 'refund_pending' partial) may omit them.
    check(
      'boring_credit_purchases_granted_check',
      sql`${table.status} IN ('refunded', 'refund_pending') OR (${table.userId} IS NOT NULL AND ${table.amountMicros} IS NOT NULL)`,
    ),
  ],
)

export const usageReservations = pgTable(
  'boring_usage_reservations',
  {
    id: uuid('id')
      .default(sql`gen_random_uuid()`)
      .primaryKey(),
    userId: text('user_id').notNull(),
    workspaceId: text('workspace_id'),
    sessionId: text('session_id'),
    runId: text('run_id').notNull(),
    source: text('source').notNull().default(''),
    amountMicros: bigint('amount_micros', { mode: 'number' }).notNull(),
    status: text('status').notNull().default('active'),
    // Durable terminal-charge intent: set true when the coordinator decided this
    // run must be charged the fallback hold (started/successful run with no billable
    // usage, or a failed usage write) BEFORE attempting the charge. If that charge
    // write then fails transiently, the stale-expiry sweep still charges the hold
    // (a marked reservation with zero billed rows is NOT freed) — so a started run
    // can't go free on a brief finalization-time DB outage.
    chargeOnExpire: boolean('charge_on_expire').notNull().default(false),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    expiresAt: timestamp('expires_at').notNull(),
  },
  (table) => [
    uniqueIndex('boring_usage_reservations_active_run_idx')
      .on(table.runId)
      .where(sql`${table.status} = 'active'`),
    index('boring_usage_reservations_user_status_idx').on(table.userId, table.status, table.expiresAt),
    check('boring_usage_reservations_amount_check', sql`${table.amountMicros} > 0`),
    check(
      'boring_usage_reservations_status_check',
      sql`${table.status} IN ('active', 'settled', 'released', 'expired')`,
    ),
  ],
)

export const budgetReservations = pgTable(
  'boring_budget_reservations',
  {
    id: uuid('id')
      .default(sql`gen_random_uuid()`)
      .primaryKey(),
    userId: text('user_id').notNull(),
    workspaceId: text('workspace_id'),
    sessionId: text('session_id'),
    runId: text('run_id').notNull(),
    scope: text('scope').notNull().default('model'),
    provider: text('provider'),
    model: text('model'),
    period: text('period').notNull(),
    amountMicros: bigint('amount_micros', { mode: 'number' }).notNull(),
    status: text('status').notNull().default('active'),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    expiresAt: timestamp('expires_at').notNull(),
  },
  (table) => [
    uniqueIndex('boring_budget_reservations_active_user_run_idx')
      .on(table.scope, table.userId, table.runId)
      .where(sql`${table.status} = 'active'`),
    index('boring_budget_reservations_budget_idx').on(table.scope, table.userId, table.provider, table.model, table.period, table.status),
    index('boring_budget_reservations_user_budget_idx').on(table.scope, table.userId, table.period, table.status),
    index('boring_budget_reservations_stale_idx').on(table.status, table.expiresAt),
    check('boring_budget_reservations_amount_check', sql`${table.amountMicros} > 0`),
    check('boring_budget_reservations_scope_check', sql`${table.scope} IN ('model', 'user')`),
    check(
      'boring_budget_reservations_scope_shape_check',
      sql`(${table.scope} = 'model' AND ${table.provider} IS NOT NULL AND length(btrim(${table.provider})) > 0 AND ${table.model} IS NOT NULL AND length(btrim(${table.model})) > 0) OR (${table.scope} = 'user' AND ${table.provider} IS NULL AND ${table.model} IS NULL)`,
    ),
    check(
      'boring_budget_reservations_status_check',
      sql`${table.status} IN ('active', 'settled', 'released', 'expired')`,
    ),
  ],
)
export const modelBudgetReservations = budgetReservations

export const usageLedger = pgTable(
  'boring_usage_ledger',
  {
    /** Caller-provided stable usage id; the idempotency key for inserts. */
    id: text('id').primaryKey(),
    userId: text('user_id').notNull(),
    workspaceId: text('workspace_id'),
    sessionId: text('session_id'),
    runId: text('run_id'),
    messageId: text('message_id'),
    source: text('source').notNull().default(''),
    provider: text('provider'),
    model: text('model'),
    inputTokens: bigint('input_tokens', { mode: 'number' }).notNull().default(0),
    outputTokens: bigint('output_tokens', { mode: 'number' }).notNull().default(0),
    cacheReadTokens: bigint('cache_read_tokens', { mode: 'number' }).notNull().default(0),
    cacheWriteTokens: bigint('cache_write_tokens', { mode: 'number' }).notNull().default(0),
    providerCostMicros: bigint('provider_cost_micros', { mode: 'number' }).notNull().default(0),
    billedCostMicros: bigint('billed_cost_micros', { mode: 'number' }).notNull(),
    stopReason: text('stop_reason'),
    metadata: jsonb('metadata').notNull().default({}),
    createdAt: timestamp('created_at').defaultNow().notNull(),
  },
  (table) => [
    index('boring_usage_ledger_user_created_idx').on(table.userId, table.createdAt),
    index('boring_usage_ledger_run_idx').on(table.runId),
    check('boring_usage_ledger_billed_check', sql`${table.billedCostMicros} >= 0`),
    check(
      'boring_usage_ledger_tokens_check',
      sql`${table.inputTokens} >= 0 AND ${table.outputTokens} >= 0 AND ${table.cacheReadTokens} >= 0 AND ${table.cacheWriteTokens} >= 0 AND ${table.providerCostMicros} >= 0`,
    ),
  ],
)

export const telemetryEvents = pgTable(
  'telemetry_events',
  {
    id: uuid('id')
      .default(sql`gen_random_uuid()`)
      .primaryKey(),
    appId: text('app_id').notNull(),
    eventName: text('event_name').notNull(),
    distinctId: text('distinct_id').notNull().default('anonymous'),
    properties: jsonb('properties').notNull().default({}),
    createdAt: timestamp('created_at').defaultNow().notNull(),
  },
  (table) => [
    index('telemetry_events_app_created_at_idx').on(table.appId, table.createdAt),
    index('telemetry_events_event_name_idx').on(table.eventName),
  ],
)

export const agentHostBindingAdmissions = pgTable(
  'agent_host_binding_admissions',
  {
    sequence: bigint('sequence', { mode: 'bigint' }).generatedAlwaysAsIdentity(),
    hostId: text('host_id').notNull(),
    bindingId: text('binding_id').notNull(),
    firstRevisionId: text('active_revision').notNull(),
    // Nullable only for immutable rows created before migration 0020; runtime admission rejects those rows as mismatches.
    executionIdentityDigest: text('execution_identity_digest'),
    firstDesiredStateDigest: text('first_desired_state_digest'),
    admittedAt: timestamp('admitted_at', { withTimezone: true }).defaultNow().notNull(),
  },
  (table) => [
    primaryKey({ name: 'agent_host_binding_admissions_pk', columns: [table.hostId, table.bindingId] }),
    uniqueIndex('agent_host_binding_admissions_sequence_unique').on(table.sequence),
    check('agent_host_binding_admissions_revision_check', sql`${table.firstRevisionId} ~ '^r[0-9]{10}$'`),
    check('agent_host_binding_admissions_execution_digest_check', sql`${table.executionIdentityDigest} ~ '^sha256:[a-f0-9]{64}$'`),
    check('agent_host_binding_admissions_desired_digest_check', sql`${table.firstDesiredStateDigest} ~ '^sha256:[a-f0-9]{64}$'`),
  ],
)

export const agentHostDestructivePublicationEvents = pgTable(
  'agent_host_destructive_publication_events',
  {
    sequence: bigint('sequence', { mode: 'bigint' }).generatedAlwaysAsIdentity().primaryKey(),
    operationId: text('operation_id').notNull(),
    state: text('state').notNull(),
    hostId: text('host_id').notNull(),
    expectedRevision: text('expected_revision').notNull(),
    expectedDigest: text('expected_digest').notNull(),
    targetRevision: text('target_revision').notNull(),
    targetDigest: text('target_digest').notNull(),
    sourceRevision: text('source_revision'),
    sourceDigest: text('source_digest'),
    removalBindingIds: text('removal_binding_ids').array().notNull(),
    recordedAt: timestamp('recorded_at', { withTimezone: true }).defaultNow().notNull(),
  },
  (table) => [
    uniqueIndex('agent_host_destructive_publication_prepared_unique').on(table.operationId).where(sql`${table.state} = 'prepared'`),
    uniqueIndex('agent_host_destructive_publication_terminal_unique').on(table.operationId).where(sql`${table.state} IN ('committed', 'aborted')`),
    check('agent_host_destructive_publication_state_check', sql`${table.state} IN ('prepared', 'committed', 'aborted')`),
    check('agent_host_destructive_publication_expected_revision_check', sql`${table.expectedRevision} ~ '^r[0-9]{10}$'`),
    check('agent_host_destructive_publication_target_revision_check', sql`${table.targetRevision} ~ '^r[0-9]{10}$'`),
    check('agent_host_destructive_publication_expected_digest_check', sql`${table.expectedDigest} ~ '^sha256:[a-f0-9]{64}$'`),
    check('agent_host_destructive_publication_target_digest_check', sql`${table.targetDigest} ~ '^sha256:[a-f0-9]{64}$'`),
    check('agent_host_destructive_publication_source_pair_check', sql`(${table.sourceRevision} IS NULL) = (${table.sourceDigest} IS NULL)`),
    check('agent_host_destructive_publication_source_revision_check', sql`${table.sourceRevision} IS NULL OR ${table.sourceRevision} ~ '^r[0-9]{10}$'`),
    check('agent_host_destructive_publication_source_digest_check', sql`${table.sourceDigest} IS NULL OR ${table.sourceDigest} ~ '^sha256:[a-f0-9]{64}$'`),
    check('agent_host_destructive_publication_removals_check', sql`cardinality(${table.removalBindingIds}) > 0`),
  ],
)
